package main

import (
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

func fileHandler(w http.ResponseWriter, r *http.Request) {
	uploadsDir := "./uploads"
	filename := r.URL.Query().Get("filename")

	// Sanitize and resolve the file path
	cleanFilename := filepath.Clean(filename)
	if strings.Contains(cleanFilename, "..") {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	filePath := filepath.Join(uploadsDir, cleanFilename)
	absFilePath, err := filepath.Abs(filePath)
	if err != nil || !strings.HasPrefix(absFilePath, filepath.Clean(uploadsDir)) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	file, err := os.Open(absFilePath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	http.ServeContent(w, r, cleanFilename, file.ModTime(), file)
}

func main() {
	http.HandleFunc("/files", fileHandler)
	http.ListenAndServe(":8080", nil)
}